export const RunBackupRecoveryDrillParams = zod.object({
  "id": zod.coerce.string().describe('Backup identifier')
})

export const runBackupRecoveryDrillBodyPassphraseMin = 12;
export const runBackupRecoveryDrillBodyPassphraseMax = 128;



export const RunBackupRecoveryDrillBody = zod.object({
  "passphrase": zod.string().min(runBackupRecoveryDrillBodyPassphraseMin).max(runBackupRecoveryDrillBodyPassphraseMax)
})

export const RunBackupRecoveryDrillResponse = zod.object({
  "valid": zod.boolean(),
  "backup_id": zod.string(),
  "verified_at": zod.coerce.date(),
  "restored_database": zod.string(),
  "table_counts_match": zod.boolean()
})


/**
 * @summary Create a pre-restore backup and restore the selected package
 */
export const RestoreEncryptedBackupParams = zod.object({
  "id": zod.coerce.string().describe('Backup identifier')
})

export const restoreEncryptedBackupBodyOnePassphraseMin = 12;
export const restoreEncryptedBackupBodyOnePassphraseMax = 128;



export const RestoreEncryptedBackupBody = zod.object({
  "passphrase": zod.string().min(restoreEncryptedBackupBodyOnePassphraseMin).max(restoreEncryptedBackupBodyOnePassphraseMax)
}).and(zod.object({
  "confirmation": zod.literal("RESTORE FOUNDERS FINANCE")
}))

export const RestoreEncryptedBackupResponse = zod.object({
  "restored": zod.boolean(),
  "backup_id": zod.string(),
  "pre_restore_backup_id": zod.string()
})


/**
 * @summary Download an encrypted backup package
 */
export const DownloadEncryptedBackupParams = zod.object({
  "id": zod.coerce.string().describe('Backup identifier')
})

export const DownloadEncryptedBackupResponse = zod.unknown()
